function saturdays(start: Date, count: number): Date[] {
  const dates: Date[] = [];
  const d = new Date(start);
  for (let i = 0; i < count; i++) {
    dates.push(new Date(d));
    d.setDate(d.getDate() + 7);
  }
  return dates;
}

