// ─────────────────────────────────────────────────────────────────────────────
// SEED FUNCTION
// ─────────────────────────────────────────────────────────────────────────────

async function seed() {
  const client = await pool.connect();
  try {
    await client.query("BEGIN");

    // 1. Delete existing mastery tests + questions
    console.log("Cleaning old mastery data...");
    const oldTests = await client.query(
      "SELECT id FROM tests WHERE test_type IN ('mastery_chapter','mastery_class','mastery_final')"
    );
    for (const row of oldTests.rows) {
      await client.query("DELETE FROM test_questions WHERE test_id=$1", [row.id]);
      await client.query("DELETE FROM tests WHERE id=$1", [row.id]);
    }
    await client.query("DELETE FROM questions WHERE source='mastery'");

    // 2. Insert mastery questions per chapter
    console.log("Inserting mastery questions...");
    const questionIdsByTopic: Record<number, number[]> = {};

    for (const topicId of Object.keys(ch) as unknown as number[]) {
      const qs = ch[topicId];
      const ids: number[] = [];
      for (const q of qs) {
        const res = await client.query(
          `INSERT INTO questions(topic_id,text,options,correct_option,explanation,difficulty,source)
           VALUES($1,$2,$3,$4,$5,$6,'mastery') RETURNING id`,
          [topicId, q.t, q.o, q.c, q.e, q.d]
        );
        ids.push(res.rows[0].id);
      }
      questionIdsByTopic[topicId] = ids;
      console.log(`  Topic ${topicId}: ${ids.length} questions inserted`);
    }

    // 3. Create tests and link questions
    console.log("Creating Saturday test schedule...");
    for (const s of schedule) {
      const testRes = await client.query(
        `INSERT INTO tests(title, description, question_count, duration_minutes, difficulty, topic_ids, test_type, scheduled_date, class_level)
         VALUES($1,$2,$3,$4,'mixed',$5,$6,$7,$8) RETURNING id`,
        [s.title, s.desc, s.qCount, s.mins, s.topicIds, s.type, s.date.toISOString().slice(0,10), s.classLevel]
      );
      const testId = testRes.rows[0].id;

      // Pick questions for this test
      let selectedQIds: number[] = [];

      if (s.type === "mastery_chapter") {
        // All 45 from the single chapter
        selectedQIds = questionIdsByTopic[s.topicIds[0]] ?? [];
      } else if (s.type === "mastery_class") {
        // 6 questions per chapter (or distributed evenly)
        const perTopic = Math.floor(s.qCount / s.topicIds.length);
        for (const tid of s.topicIds) {
          const ids = questionIdsByTopic[tid] ?? [];
          selectedQIds.push(...ids.slice(0, perTopic));
        }
        // Fill remaining if needed
        const remaining = s.qCount - selectedQIds.length;
        if (remaining > 0) {
          for (const tid of s.topicIds) {
            const ids = (questionIdsByTopic[tid] ?? []).slice(Math.floor(s.qCount / s.topicIds.length));
            selectedQIds.push(...ids.slice(0, remaining - selectedQIds.length + (Math.floor(s.qCount / s.topicIds.length) * s.topicIds.length)));
            if (selectedQIds.length >= s.qCount) break;
          }
          selectedQIds = selectedQIds.slice(0, s.qCount);
        }
      } else if (s.type === "mastery_final") {
        // 6 questions per chapter from all 29 topics
        const perTopic = Math.floor(s.qCount / s.topicIds.length);
        for (const tid of s.topicIds) {
          const ids = questionIdsByTopic[tid] ?? [];
          selectedQIds.push(...ids.slice(0, perTopic));
        }
        // Top up to 180
        let idx = 0;
        while (selectedQIds.length < s.qCount && idx < s.topicIds.length) {
          const tid = s.topicIds[idx];
          const ids = (questionIdsByTopic[tid] ?? []).slice(perTopic);
          if (ids.length > 0) selectedQIds.push(ids[0]);
          idx++;
        }
        selectedQIds = selectedQIds.slice(0, s.qCount);
      }

      // Update question_count to actual
      await client.query("UPDATE tests SET question_count=$1 WHERE id=$2", [selectedQIds.length, testId]);

      // Insert test_questions
      for (let i = 0; i < selectedQIds.length; i++) {
        await client.query(
          "INSERT INTO test_questions(test_id,question_id,order_index) VALUES($1,$2,$3)",
          [testId, selectedQIds[i], i]
        );
      }
      console.log(`  ${s.date.toISOString().slice(0,10)} | ${s.title}: ${selectedQIds.length} questions`);
    }

    await client.query("COMMIT");
    console.log("\n✅ Mastery Test Series seeded successfully!");
    console.log(`   Total new questions: ${Object.values(ch).reduce((a,b)=>a+b.length,0)}`);
    console.log(`   Total tests created: ${schedule.length}`);
  } catch (err) {
    await client.query("ROLLBACK");
    console.error("Error:", err);
    throw err;
  } finally {
    client.release();
    await pool.end();
  }
}

seed();
